<h3>Model Essays</h3>
<form class="row g-2 mb-3"><div class="col"><select name="topic_id" class="form-select"><option value="">All topics</option><?php foreach($topics as $t): ?><option value="<?= $t['id'] ?>" <?= ((string)($t['id'])===($_GET['topic_id']??''))?'selected':'' ?>><?= e($t['title']) ?></option><?php endforeach; ?></select></div><div class="col"><select name="level" class="form-select"><option value="">All levels</option><?php foreach(['A2','B1','B2','C1'] as $l): ?><option <?= (($_GET['level']??'')===$l)?'selected':'' ?>><?=$l?></option><?php endforeach; ?></select></div><div class="col"><button class="btn btn-primary">Filter</button></div></form>
<?php foreach($essays as $e): ?><div class="card mb-2"><div class="card-body"><h5><?= e($e['title']) ?> <span class="badge bg-success">Band <?= e((string)$e['overall']) ?></span></h5><p><small><?= e($e['topic_title']) ?> | <?= e($e['level']) ?></small></p><p><?= nl2br(e(substr($e['content'],0,280))) ?>...</p></div></div><?php endforeach; ?>
